const results = [];
for (const inputItem of $input.all()) {
  let ideas = inputItem.json.output || inputItem.json.content;
  if (typeof ideas === 'string') {
    ideas = ideas.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
    ideas = JSON.parse(ideas);
  }
  for (const idea of ideas) {
    results.push({ json: { tema: idea.tema || '', palabras: idea.palabras || '', categoria: idea.categoria || '', Meta_descripcion: idea.meta_descripcion || idea.Meta_descripcion || '', tags: idea.tags || idea.Tags || [] } });
  }
}
return results;

const source = $input.item.json;

// 1. Extraer el texto crudo de la respuesta de OpenRouter
let rawText = '';
if (typeof source?.choices?.[0]?.message?.content === 'string') {
  rawText = source.choices[0].message.content;
} else if (Array.isArray(source?.choices?.[0]?.message?.content)) {
  rawText = source.choices[0].message.content
    .map((part) => (typeof part === 'string' ? part : part?.text || ''))
    .join('');
} else if (source?.content?.parts?.[0]?.text) {
  rawText = source.content.parts[0].text;
} else if (typeof source === 'string') {
  rawText = source;
} else {
  rawText = JSON.stringify(source);
}

// 2. Limpiar markdown fences
rawText = rawText
  .replace(/```json\s*/gi, '')
  .replace(/```\s*/g, '')
  .trim();

// 3. Intentar parsear el JSON directamente primero
let parsed = null;
try {
  parsed = JSON.parse(rawText);
} catch (_) {}

// 4. Si falla, buscar el primer objeto JSON válido dentro del texto
if (!parsed) {
  function extractFirstJsonObject(text) {
    const start = text.indexOf('{');
    if (start === -1) return null;
    let depth = 0, inString = false, escape = false;
    for (let i = start; i < text.length; i++) {
      const ch = text[i];
      if (escape) { escape = false; continue; }
      if (ch === '\\') { escape = true; continue; }
      if (ch === '"') { inString = !inString; continue; }
      if (inString) continue;
      if (ch === '{') depth++;
      if (ch === '}') depth--;
      if (depth === 0) return text.slice(start, i + 1);
    }
    return null;
  }

  const jsonString = extractFirstJsonObject(rawText);
  if (!jsonString) {
    throw new Error('No se encontró JSON válido. Respuesta: ' + rawText.substring(0, 700));
  }
  try {
    parsed = JSON.parse(jsonString);
  } catch (e) {
    throw new Error('Parse fallido: ' + e.message + '. Texto: ' + rawText.substring(0, 700));
  }
}

// 5. Validar que los campos críticos están presentes
const missing = ['title', 'excerpt', 'content'].filter(f => !parsed[f]);
if (missing.length > 0) {
  throw new Error(
    `El modelo no devolvió los campos: ${missing.join(', ')}. ` +
    `Respuesta parseada: ${JSON.stringify(parsed).substring(0, 500)}`
  );
}

return [{ json: parsed }];

const data = $input.first().json;
const rawTags = data.tags || data.Tags || [];
const tagsArray = Array.isArray(rawTags)
  ? rawTags.map(t => String(t || '').trim()).filter(Boolean)
  : String(rawTags || '').split(',').map(t => t.trim()).filter(Boolean);
const categorySlug = String(data.categoria || data.category_slug || 'ia')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-+|-+$/g, '') || 'ia';
const wpBody = { title: data.title, excerpt: data.excerpt, content: data.content, status: 'published', category_slug: categorySlug, tags: tagsArray, featured_image: data.imagen_destacada_url, meta_description: data.meta_description || data.meta_descripcion || data.excerpt.substring(0, 160) };
return { json: { wpBody, ...data, tags: tagsArray, category_slug: categorySlug } };

const item = $input.all()[0];
let content = item.json;

if (typeof content === 'string') {
  try {
    content = JSON.parse(content);
  } catch (e) {
    throw new Error(`Parse error: ${e.message}`);
  }
}

let editorialContext = {};
try {
  editorialContext = $('Preparar contexto editorial').first().json || {};
} catch (e) {}

if (!content.Tags) {
  for (const i of $input.all()) {
    if (i.json.Tags) {
      content.Tags = i.json.Tags;
      break;
    }
  }

  if (!content.Tags && editorialContext.Tags) {
    content.Tags = editorialContext.Tags;
  }
}

content.categoria = content.categoria || editorialContext.categoria || 'ia';
content.imagen_destacada_url = content.imagen_destacada_url || editorialContext.imagen_destacada_url || editorialContext.featured_image || '';
content.imagen_body1_url = content.imagen_body1_url || editorialContext.imagen_body1_url || '';
content.imagen_body2_url = content.imagen_body2_url || editorialContext.imagen_body2_url || '';

const missing = ['title', 'excerpt', 'content'].filter((f) => !content[f]);
if (missing.length > 0) {
  throw new Error(`Campos faltantes: ${missing.join(', ')}`);
}

if (!content.featured_media) content.featured_media = 1;

if (!content.meta_description?.trim()) {
  content.meta_description = editorialContext.meta_descripcion || content.excerpt.substring(0, 160);
}

if (content.excerpt?.length > 160) {
  content.excerpt = content.excerpt.substring(0, 157) + '...';
}

if (content.meta_description?.length > 160) {
  content.meta_description = content.meta_description.substring(0, 157) + '...';
}

return { json: content };

const rawItems = $input.all();
const source = rawItems.length === 1 && Array.isArray(rawItems[0].json?.data) ? rawItems[0].json.data : rawItems.map(i => i.json);
const enlacesBlogs = source.map(post => ({ titulo: post.title, url: `https://lookitry.com/blog/${post.slug}` }));
return [{ json: { enlacesBlogs } }];

const allItems = $input.all();
const datosFinales = {};
const t = allItems.find(i => i.json.tema && i.json.palabras);
if (t) Object.keys(t.json).forEach(k => { datosFinales[k] = t.json[k]; });
const img = allItems.find(i => i.json.imagen_destacada);
if (img) {
  ['imagen_destacada','imagen_body1','imagen_body2'].forEach(k => {
    datosFinales[k] = img.json[k];
    datosFinales[`${k}_url`] = img.json[k]?.url;
    datosFinales[`${k}_id`] = img.json[k]?.id;
  });
}
const e = allItems.find(i => Array.isArray(i.json.enlacesBlogs));
if (e) datosFinales.enlacesBlogs = e.json.enlacesBlogs;
if (datosFinales.Tags) {
  if (typeof datosFinales.Tags === 'string') datosFinales.Tags = datosFinales.Tags.split(',').map(t => t.trim()).filter(Boolean);
  else if (Array.isArray(datosFinales.Tags)) datosFinales.Tags = datosFinales.Tags.filter(Boolean);
}
return [{ json: datosFinales }];

const imgs = $input.first().json;
const orig = $('Obtener Temas').first().json;
return { json: { tema: orig.tema, palabras: orig.palabras, categoria: orig.categoria || 'ia', meta_descripcion: orig.Meta_descripcion || orig.meta_descripcion || '', Tags: orig.Tags || orig.tags || [], imagen_destacada_url: imgs.imagen_destacada.url, imagen_destacada_id: imgs.imagen_destacada.id, imagen_body1_url: imgs.imagen_body1.url, imagen_body1_id: imgs.imagen_body1.id, imagen_body2_url: imgs.imagen_body2.url, imagen_body2_id: imgs.imagen_body2.id } };

const items = $input.all().sort((a, b) => (a.json.orden || 0) - (b.json.orden || 0));
if (items.length < 3) {
  throw new Error(`Filtrado recibi? ${items.length} im?genes; se esperaban 3.`);
}
const mapImg = (item) => ({ id: item?.json?.id, url: item?.json?.file_url || item?.json?.url || item?.json?.source_url || null });
return [{ json: { imagen_destacada: mapImg(items[0]), imagen_body1: mapImg(items[1]), imagen_body2: mapImg(items[2]) } }];

const raw =
  $input.first()?.json?.content?.parts?.[0]?.text ||
  $input.first()?.json?.choices?.[0]?.message?.content ||
  $input.first()?.json?.text ||
  '';

if (!raw || typeof raw !== 'string') {
  throw new Error('El nodo generador no devolvió texto utilizable para extraer prompts.');
}

const text = raw.replace(/\r/g, '').trim();

function cleanPrompt(value) {
  return (value || '')
    .replace(/^["'`]+|["'`]+$/g, '')
    .replace(/\n+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function extractLabeled(label, nextLabels = []) {
  const nextPart = nextLabels.length ? `(?=\\(${nextLabels.join('|')}\\)|$)` : '$';
  const regex = new RegExp(`\\(${label}\\)\\s*([\\s\\S]+?)${nextPart}`, 'i');
  return cleanPrompt(text.match(regex)?.[1] || '');
}

let promptA = extractLabeled('A', ['B', 'C']);
let promptB = extractLabeled('B', ['C']);
let promptC = extractLabeled('C', []);

const bulletLines = text
  .split('\n')
  .map((line) => cleanPrompt(line.replace(/^[-*•\d.)\s]+/, '')))
  .filter(Boolean);

if (!promptA && bulletLines[0]) promptA = bulletLines[0];
if (!promptB && bulletLines[1]) promptB = bulletLines[1];
if (!promptC && bulletLines[2]) promptC = bulletLines[2];

// Fallback: si solo llegó un prompt válido, derivar variantes sin romper el flujo
if (promptA && !promptB) {
  promptB = `${promptA}, editorial lifestyle scene, supporting in-article visual, different composition`;
}
if (promptA && !promptC) {
  promptC = `${promptA}, secondary supporting visual, alternate camera angle, contextual ecommerce detail`;
}

// Si no vino A, intentar usar cualquier texto completo razonable
if (!promptA && text.length > 20) {
  promptA = cleanPrompt(text);
  promptB = promptB || `${promptA}, editorial lifestyle scene, supporting in-article visual`;
  promptC = promptC || `${promptA}, alternate composition, ecommerce context`;
}

if (!promptA || !promptB || !promptC) {
  throw new Error(
    `Prompts no extraídos. A:${!!promptA} B:${!!promptB} C:${!!promptC}. Texto recibido: ${text.substring(0, 800)}`
  );
}

return [
  {
    json: {
      prompt: promptA,
      tipo: 'destacada',
      orden: 1,
    },
  },
  {
    json: {
      prompt: promptB,
      tipo: 'body1',
      orden: 2,
    },
  },
  {
    json: {
      prompt: promptC,
      tipo: 'body2',
      orden: 3,
    },
  },
];

const response = $input.item.json;
const currentItem = $('Loop Imagenes Replicate').first().json;
const token = '***REMOVED-SECRET***';

async function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function getPrediction(url) {
  const res = await fetch(url, {
    headers: {
      Authorization: `Bearer ${token}`,
      'Content-Type': 'application/json',
    },
  });

  if (!res.ok) {
    const body = await res.text();
    throw new Error(`Replicate lookup failed (${res.status}): ${body}`);
  }

  return await res.json();
}

async function resolvePrediction(prediction) {
  let current = prediction;

  for (let i = 0; i < 24; i++) {
    if (current?.error) {
      throw new Error(`Replicate error en ${currentItem.tipo}: ${current.error}`);
    }

    if (current?.status === 'failed' || current?.status === 'canceled') {
      throw new Error(`Replicate termin? en ${current.status}. ID: ${current.id}`);
    }

    if (current?.status === 'succeeded' && current?.output) {
      const imageUrl = Array.isArray(current.output) ? current.output[0] : current.output;
      return [{
        json: {
          ...currentItem,
          imageUrl,
          predictionId: current.id,
          predictionStatus: current.status,
        },
      }];
    }

    const pollUrl = current?.urls?.get;
    if (!pollUrl) {
      throw new Error(`Replicate no devolvi? output ni poll URL. Status: ${current?.status || 'unknown'}`);
    }

    await sleep(5000);
    current = await getPrediction(pollUrl);
  }

  throw new Error(`Replicate no termin? a tiempo para ${currentItem.tipo}`);
}

return await resolvePrediction(response);

const item = $input.item;
const tipo = item.json.tipo || 'imagen';
const orden = item.json.orden || 1;

if (item.binary?.data) {
  item.binary.data.fileName = `${tipo}.png`;
  item.binary.data.mimeType = 'image/png';
}

return {
  json: {
    ...item.json,
    tipo,
    orden,
  },
  binary: item.binary,
};

const response = $input.item.json;
const inputData = $('Extraer Prompts').item.json;
if (response.error) throw new Error(`Error OpenRouter '${inputData.tipo}': ${response.error.message}`);
const url = response.choices?.[0]?.message?.images?.[0]?.image_url?.url;
if (!url) { console.log('Respuesta:', JSON.stringify(response, null, 2)); throw new Error(`No hay URL de imagen para '${inputData.tipo}'.`); }
const base64Data = url.split('base64,')[1];
if (!base64Data) throw new Error(`No se pudo extraer base64 para '${inputData.tipo}'.`);
console.log(`✓ OpenRouter ${inputData.tipo}: ${base64Data.length} chars`);
return { json: { ...inputData, base64: base64Data } };

const item = $input.item;
const itemIndex = $itemIndex;
let tipo, orden;
try { const d = $('Extraer Prompts').all()[itemIndex]?.json; if (d?.tipo) { tipo = d.tipo; orden = d.orden; } } catch(e) {}
if (!tipo) { tipo = item.json.tipo || 'imagen'; orden = item.json.orden || itemIndex + 1; }
if (item.binary?.data) { item.binary.data.fileName = `${tipo}.webp`; item.binary.data.mimeType = 'image/webp'; }
console.log(`OpenRouter renombrado: ${tipo}.webp`);
return { json: { ...item.json, tipo, orden }, binary: item.binary };
